const char *CODEGEN_WARNING =
    "// This file is automatically generated by tools/code_gen.c\n"
    "// Please do not edit it directly\n\n";

int eolib_mkdir(const char *path)
{
#if defined(_WIN32)
    return _mkdir(path);
#else
    return mkdir(path, 0755);
#endif
}

void *xmalloc(size_t size)
{
    void *ptr = malloc(size);
    if (!ptr)
    {
        fprintf(stderr, "Out of memory\n");
        exit(1);
    }
    return ptr;
}

char *xstrdup(const char *value)
{
    if (!value)
    {
        return NULL;
    }
    char *dup = strdup(value);
    if (!dup)
    {
        fprintf(stderr, "Out of memory\n");
        exit(1);
    }
    return dup;
}

void element_list_push(ElementList *list, StructElement element)
{
    if (list->elements_count >= list->elements_capacity)
    {
        list->elements_capacity = ARRAY_GROW_CAPACITY(list->elements_capacity);
        list->elements =
            realloc(list->elements, list->elements_capacity * sizeof(StructElement));
        if (!list->elements)
        {
            fprintf(stderr, "Out of memory\n");
            exit(1);
        }
    }
    list->elements[list->elements_count++] = element;
}

